import React, { useState, useEffect, useRef } from 'react';
import { NavLink, useLocation, Link } from 'react-router-dom';
import { ShoppingBag, Menu, X, LogOut, LayoutDashboard, Heart } from 'lucide-react';
import { useCart } from '../../context/CartContext';
import { useAuth } from '../../context/AuthContext';
import { motion, AnimatePresence } from 'framer-motion';

export default function Navbar() {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const { totalItems } = useCart();
  const { user, logout, isAdmin } = useAuth();
  const location = useLocation();
  const dropdownRef = useRef(null);

  const isHome = location.pathname === '/';

  const [bounceKey, setBounceKey] = useState(0);
  const prevTotal = useRef(totalItems);

  useEffect(() => {
    if (totalItems > prevTotal.current) {
      setBounceKey(prev => prev + 1);
    }
    prevTotal.current = totalItems;
  }, [totalItems]);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    setIsMobileMenuOpen(false);
    setIsDropdownOpen(false);
  }, [location.pathname]);

  // Close dropdown on outside click
  useEffect(() => {
    const handleClickOutside = (e) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target)) {
        setIsDropdownOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const navClasses = `fixed w-full top-0 z-50 transition-all duration-300 ${
    isHome && !isScrolled
      ? 'bg-transparent text-white py-6'
      : 'bg-soft-white/95 backdrop-blur-md shadow-sm text-deep-brown py-4'
  }`;

  const linkClasses = ({ isActive }) =>
    `uppercase tracking-widest text-sm font-medium transition-colors hover:text-rose-gold ${
      isActive ? 'text-rose-gold' : ''
    }`;

  const getInitials = () => {
    const name = user?.displayName || user?.email || 'U';
    return name.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2);
  };

  return (
    <nav className={navClasses}>
      <div className="max-w-7xl mx-auto px-6 lg:px-8">
        <div className="flex justify-between items-center">

          {/* Mobile Menu Button */}
          <div className="md:hidden flex items-center">
            <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}>
              {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
            </button>
          </div>

          {/* Logo */}
          <div className="flex-1 md:flex-none flex justify-center md:justify-start">
            <Link to="/" className="font-display text-3xl font-semibold">
              <span className={isHome && !isScrolled ? 'text-white' : 'text-shimmer'}>
                DNC Creates
              </span>
            </Link>
          </div>

          {/* Desktop Links */}
          <div className="hidden md:flex flex-1 justify-center space-x-10">
            <NavLink to="/" className={linkClasses}>Home</NavLink>
            <NavLink to="/shop" className={linkClasses}>Shop</NavLink>
            <NavLink to="/about" className={linkClasses}>About</NavLink>
            <NavLink to="/contact" className={linkClasses}>Contact</NavLink>
          </div>

          {/* Right: Admin + Cart + User */}
          <div className="flex items-center justify-end gap-4">
            {/* Admin Panel Icon — only for admin */}
            {isAdmin && (
              <Link
                to="/admin"
                title="Admin Panel"
                className="relative hover:text-rose-gold transition-colors"
              >
                <LayoutDashboard size={22} strokeWidth={1.5} />
              </Link>
            )}

            {/* Wishlist Icon */}
            {user && (
              <Link to="/wishlist" className="relative hover:text-rose-gold transition-colors" title="Wishlist">
                <Heart size={24} strokeWidth={1.5} />
              </Link>
            )}

            {/* Cart Icon */}
            <Link to="/cart" className="relative hover:text-rose-gold transition-colors block">
              <motion.div
                key={bounceKey}
                animate={bounceKey > 0 ? { scale: [1, 1.3, 0.9, 1.1, 1] } : {}}
                transition={{ duration: 0.4, ease: "easeInOut" }}
              >
                <ShoppingBag size={24} strokeWidth={1.5} />
              </motion.div>
              <AnimatePresence>
                {totalItems > 0 && (
                  <motion.span 
                    key={totalItems}
                    initial={{ y: 10, opacity: 0, scale: 0.5 }}
                    animate={{ y: 0, opacity: 1, scale: 1 }}
                    exit={{ y: -10, opacity: 0, scale: 0.5 }}
                    transition={{ duration: 0.2 }}
                    className="absolute -top-2 -right-2 bg-rose-gold text-white text-[10px] font-bold h-5 w-5 rounded-full flex items-center justify-center transform origin-center"
                  >
                    {totalItems}
                  </motion.span>
                )}
              </AnimatePresence>
            </Link>

            {/* User / Auth */}
            {user ? (
              <div className="relative" ref={dropdownRef}>
                <button
                  onClick={() => setIsDropdownOpen(!isDropdownOpen)}
                  className="w-9 h-9 rounded-full bg-rose-gold text-white flex items-center justify-center text-sm font-medium overflow-hidden hover:ring-2 hover:ring-rose-gold/50 transition-all"
                  aria-label="User menu"
                >
                  {user.photoURL ? (
                    <img src={user.photoURL} alt="avatar" className="w-full h-full object-cover" />
                  ) : (
                    getInitials()
                  )}
                </button>
                <AnimatePresence>
                  {isDropdownOpen && (
                    <motion.div
                      initial={{ opacity: 0, y: -8, scale: 0.95 }}
                      animate={{ opacity: 1, y: 0, scale: 1 }}
                      exit={{ opacity: 0, y: -8, scale: 0.95 }}
                      transition={{ duration: 0.15 }}
                      className="absolute right-0 mt-2 w-48 bg-white shadow-lg border border-rose-gold/10 rounded-sm overflow-hidden"
                    >
                      <div className="px-4 py-3 border-b border-rose-gold/10">
                        <p className="text-xs text-deep-brown/50 uppercase tracking-wider">Logged in as</p>
                        <p className="text-sm font-medium text-deep-brown truncate">{user.displayName || user.email}</p>
                      </div>
                      <Link
                        to="/orders"
                        className="w-full flex items-center gap-2 px-4 py-3 text-sm text-deep-brown/70 hover:text-rose-gold hover:bg-rose-gold/5 transition-colors border-b border-rose-gold/5"
                      >
                        <ShoppingBag size={14} />
                        Order History
                      </Link>
                      {isAdmin && (
                        <Link
                          to="/admin"
                          className="w-full flex items-center gap-2 px-4 py-3 text-sm text-deep-brown/70 hover:text-rose-gold hover:bg-rose-gold/5 transition-colors"
                        >
                          <LayoutDashboard size={14} />
                          Admin Panel
                        </Link>
                      )}
                      <button
                        onClick={logout}
                        className="w-full flex items-center gap-2 px-4 py-3 text-sm text-deep-brown/70 hover:text-red-500 hover:bg-red-50 transition-colors"
                      >
                        <LogOut size={14} />
                        Logout
                      </button>
                    </motion.div>
                  )}
                </AnimatePresence>
              </div>
            ) : (
              <Link
                to="/login"
                className={`hidden md:block uppercase tracking-widest text-sm font-medium transition-colors hover:text-rose-gold ${isHome && !isScrolled ? 'text-white/80' : 'text-deep-brown/60'}`}
              >
                Login
              </Link>
            )}
          </div>
        </div>
      </div>

      {/* Mobile Menu */}
      <AnimatePresence>
        {isMobileMenuOpen && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            className="md:hidden bg-soft-white border-t border-rose-gold/20 overflow-hidden"
          >
            <div className="flex flex-col px-6 py-6 space-y-4 text-deep-brown">
              <NavLink to="/" className={linkClasses}>Home</NavLink>
              <NavLink to="/shop" className={linkClasses}>Shop</NavLink>
              <NavLink to="/about" className={linkClasses}>About</NavLink>
              <NavLink to="/contact" className={linkClasses}>Contact</NavLink>
              {!user && (
                <NavLink to="/login" className={linkClasses}>Login</NavLink>
              )}
              {user && (
                <NavLink to="/orders" className={linkClasses}>Order History</NavLink>
              )}
              {user && isAdmin && (
                <NavLink to="/admin" className={linkClasses}>Admin Panel</NavLink>
              )}
              {user && (
                <button onClick={logout} className="text-left uppercase tracking-widest text-sm font-medium text-red-400 hover:text-red-600 transition-colors">
                  Logout
                </button>
              )}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </nav>
  );
}

import React from 'react';
import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import { Heart } from 'lucide-react';
import { useWishlist } from '../../context/WishlistContext';

export default function ProductCard({ product }) {
  const { toggleWishlist, isInWishlist } = useWishlist();
  const isWished = isInWishlist(product.id);

  const handleWishlistClick = (e) => {
    e.preventDefault();
    e.stopPropagation();
    toggleWishlist(product.id);
  };

  return (
    <motion.div 
      whileHover={{ y: -5 }}
      className="group relative flex flex-col h-full bg-soft-white/40 cursor-pointer"
    >
      <Link to={`/shop/${product.id}`} className="block h-full flex flex-col relative overflow-hidden">
        {/* Badge */}
        {!product.inStock ? (
          <div className="absolute top-4 left-4 z-20 bg-gray-500 text-white text-xs font-body uppercase tracking-wider px-3 py-1">
            Out of Stock
          </div>
        ) : product.badge ? (
          <div className="absolute top-4 left-4 z-20 bg-rose-gold text-white text-xs font-body uppercase tracking-wider px-3 py-1">
            {product.badge}
          </div>
        ) : null}

        <button 
          onClick={handleWishlistClick}
          className="absolute top-4 right-4 z-20 w-8 h-8 rounded-full bg-white/70 backdrop-blur-sm flex items-center justify-center text-rose-gold hover:bg-rose-gold hover:text-white transition-colors shadow-sm"
          aria-label="Add to Wishlist"
        >
          <Heart size={16} fill={isWished ? 'currentColor' : 'none'} strokeWidth={isWished ? 0 : 2} />
        </button>

        {/* Image Box */}
        <div className="aspect-square w-full overflow-hidden bg-champagne mb-4 relative">
          <img 
            src={product.imageUrl || product.image || (product.imageUrls && product.imageUrls[0])} 
            alt={product.name} 
            className={`w-full h-full object-cover transition-transform duration-700 ease-out group-hover:scale-105 ${!product.inStock ? 'opacity-60 grayscale' : ''}`}
          />
          {/* Overlay gradient for a premium feel on hover */}
          <div className="absolute inset-0 bg-deep-brown/0 group-hover:bg-deep-brown/10 transition-colors duration-300 pointer-events-none" />
          {!product.inStock && (
            <div className="absolute inset-0 bg-white/30 backdrop-grayscale pointer-events-none z-10" />
          )}
        </div>

        {/* Details Box */}
        <div className="px-2 pb-4 flex flex-col flex-grow text-center">
          <span className="text-rose-gold/70 text-xs font-body uppercase tracking-widest mb-2 block">
            {product.category}
          </span>
          <h3 className="font-display text-lg text-deep-brown mb-2 leading-snug">
            {product.name}
          </h3>
          <div className="mt-auto flex items-center justify-center space-x-2">
            <span className="font-body text-deep-brown font-medium">₹{product.price}</span>
            {product.originalPrice && (
              <span className="font-body text-deep-brown/40 line-through text-sm">
                ₹{product.originalPrice}
              </span>
            )}
          </div>
        </div>
      </Link>
    </motion.div>
  );
}

import React, { createContext, useContext, useState, useEffect } from 'react';
import { 
  signInWithPopup, GoogleAuthProvider, 
  signInWithEmailAndPassword, 
  createUserWithEmailAndPassword, 
  signOut, onAuthStateChanged,
  updateProfile
} from 'firebase/auth';
import { doc, getDoc, setDoc } from 'firebase/firestore';
import { auth, db } from '../firebase';

const AuthContext = createContext();

export function useAuth() {
  return useContext(AuthContext);
}

export function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  const isAdmin = user?.email === import.meta.env.VITE_ADMIN_EMAIL;

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (currentUser) => {
      if (currentUser) {
        // Fetch or create user doc
        const userRef = doc(db, 'users', currentUser.uid);
        const userDoc = await getDoc(userRef);

        if (!userDoc.exists()) {
          await setDoc(userRef, {
            displayName: currentUser.displayName,
            email: currentUser.email,
            photoURL: currentUser.photoURL,
            createdAt: new Date().toISOString(),
            role: 'user'
          });
        }
      }
      setUser(currentUser);
      setLoading(false);
    });

    return unsubscribe;
  }, []);

  const loginWithGoogle = async () => {
    const provider = new GoogleAuthProvider();
    return signInWithPopup(auth, provider);
  };

  const loginWithEmail = (email, password) => {
    return signInWithEmailAndPassword(auth, email, password);
  };

  const registerWithEmail = async (email, password, displayName) => {
    const userCredential = await createUserWithEmailAndPassword(auth, email, password);
    await updateProfile(userCredential.user, { displayName });
    return userCredential;
  };

  const logout = () => {
    return signOut(auth);
  };

  const value = {
    user,
    loading,
    isAdmin,
    loginWithGoogle,
    loginWithEmail,
    registerWithEmail,
    logout
  };

  return (
    <AuthContext.Provider value={value}>
      {!loading && children}
    </AuthContext.Provider>
  );
}

