import React, { createContext, useContext, useState, useEffect } from 'react';
import { doc, getDoc, setDoc, onSnapshot } from 'firebase/firestore';
import { db } from '../firebase';
import { useAuth } from './AuthContext';

const CartContext = createContext();

export function useCart() {
  return useContext(CartContext);
}

export function CartProvider({ children }) {
  const { user } = useAuth();
  const [items, setItems] = useState([]);
  const [syncing, setSyncing] = useState(false);

  // Load from local storage initially if not logged in
  useEffect(() => {
    if (!user) {
      const saved = localStorage.getItem('dnc-cart');
      if (saved) {
        try {
          setItems(JSON.parse(saved));
        } catch (error) {
          setItems([]);
        }
      }
    }
  }, [user]);

  // Sync with Firestore when user logs in/changes
  useEffect(() => {
    if (!user) return;

    const cartRef = doc(db, 'carts', user.uid);
    let unsubscribe = () => {};

    const syncCart = async () => {
      setSyncing(true);
      const cartDoc = await getDoc(cartRef);
      const localCartStr = localStorage.getItem('dnc-cart');
      let localCart = [];
      try {
        if (localCartStr) localCart = JSON.parse(localCartStr);
      } catch (e) {}

      let mergedItems = [];
      if (cartDoc.exists()) {
        const firestoreCart = cartDoc.data().items || [];
        // Merging: Combine items based on ID
        const combined = [...firestoreCart];
        for (const localItem of localCart) {
          const existing = combined.find(i => i.id === localItem.id);
          if (existing) {
            existing.qty = Math.max(existing.qty, localItem.qty);
          } else {
            combined.push(localItem);
          }
        }
        mergedItems = combined;
      } else {
        mergedItems = localCart;
      }

      await setDoc(cartRef, { items: mergedItems, updatedAt: new Date().toISOString() }, { merge: true });
      localStorage.removeItem('dnc-cart'); // Clear local cart after merge

      // Setup listener
      unsubscribe = onSnapshot(cartRef, (docSnap) => {
        if (docSnap.exists()) {
          setItems(docSnap.data().items || []);
        } else {
          setItems([]);
        }
        setSyncing(false);
      });
    };

    syncCart();

    return () => unsubscribe();
  }, [user]);

  // Update logic
  const saveCart = async (newItems) => {
    setItems(newItems);
    if (user) {
      setSyncing(true);
      await setDoc(doc(db, 'carts', user.uid), {
        items: newItems,
        updatedAt: new Date().toISOString()
      }, { merge: true });
      setSyncing(false);
    } else {
      localStorage.setItem('dnc-cart', JSON.stringify(newItems));
    }
  };

  const addItem = (product) => {
    const existing = items.find(item => item.id === product.id);
    let newItems;
    if (existing) {
      newItems = items.map(item => 
        item.id === product.id ? { ...item, qty: item.qty + 1 } : item
      );
    } else {
      const cartItem = {
        id: product.id,
        name: product.name,
        category: product.category,
        price: product.price,
        image: product.image || product.imageUrl || null, // handle different image keys
        qty: 1
      };
      newItems = [...items, cartItem];
    }
    saveCart(newItems);
  };

  const removeItem = (id) => {
    saveCart(items.filter(item => item.id !== id));
  };

  const updateQty = (id, qty) => {
    if (qty < 1) {
      removeItem(id);
      return;
    }
    saveCart(items.map(item => 
      item.id === id ? { ...item, qty } : item
    ));
  };

  const clearCart = () => saveCart([]);

  const totalItems = items.reduce((sum, item) => sum + item.qty, 0);
  const totalPrice = items.reduce((sum, item) => sum + (item.price * item.qty), 0);

  const value = {
    items,
    syncing,
    addItem,
    removeItem,
    updateQty,
    clearCart,
    totalItems,
    totalPrice
  };

  return (
    <CartContext.Provider value={value}>
      {children}
    </CartContext.Provider>
  );
}

import React, { createContext, useContext, useState, useEffect } from 'react';
import { doc, getDoc, setDoc } from 'firebase/firestore';
import { db } from '../firebase';
import { useAuth } from './AuthContext';

const WishlistContext = createContext();

export function useWishlist() {
  return useContext(WishlistContext);
}

export function WishlistProvider({ children }) {
  const { user } = useAuth();
  const [wishlist, setWishlist] = useState([]);
  const [loading, setLoading] = useState(true);

  // Load wishlist on auth state change
  useEffect(() => {
    let isMounted = true;

    async function loadWishlist() {
      if (!user) {
        if (isMounted) {
          setWishlist([]);
          setLoading(false);
        }
        return;
      }

      setLoading(true);
      try {
        const userRef = doc(db, 'users', user.uid);
        const userDoc = await getDoc(userRef);

        if (userDoc.exists() && userDoc.data().wishlist) {
          if (isMounted) setWishlist(userDoc.data().wishlist);
        }
      } catch (error) {
        console.error("Error loading wishlist:", error);
      } finally {
        if (isMounted) setLoading(false);
      }
    }

    loadWishlist();

    return () => { isMounted = false; };
  }, [user]);

  // Sync with Firestore whenever updated locally
  const syncWishlist = async (newWishlist) => {
    if (!user) return;
    try {
      const userRef = doc(db, 'users', user.uid);
      await setDoc(userRef, { wishlist: newWishlist }, { merge: true });
    } catch (error) {
      console.error("Error saving wishlist:", error);
    }
  };

  const toggleWishlist = async (productId) => {
    if (!user) {
      alert("Please login to save items to your wishlist.");
      return;
    }

    setWishlist(prev => {
      const newWishlist = prev.includes(productId) 
        ? prev.filter(id => id !== productId)
        : [...prev, productId];

      // Async sync
      syncWishlist(newWishlist);
      return newWishlist;
    });
  };

  const isInWishlist = (productId) => {
    return wishlist.includes(productId);
  };

  return (
    <WishlistContext.Provider value={{ wishlist, loading, toggleWishlist, isInWishlist }}>
      {children}
    </WishlistContext.Provider>
  );
}

import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { ShoppingBag, MessageCircle, Trash2, Plus, Minus, Loader2 } from 'lucide-react';
import { useCart } from '../context/CartContext';
import { useAuth } from '../context/AuthContext';
import { db } from '../firebase';
import { collection, addDoc, serverTimestamp } from 'firebase/firestore';

export default function Cart() {
  const { items, updateQty, removeItem, clearCart, totalItems, totalPrice } = useCart();
  const { user } = useAuth();
  const navigate = useNavigate();
  const [isProcessing, setIsProcessing] = React.useState(false);

  const shipping = totalPrice > 999 ? 0 : 99;
  const grandTotal = totalPrice + shipping;
  const hasOutOfStock = items.some(item => item.inStock === false);

  const whatsappNumber = import.meta.env.VITE_OWNER_WHATSAPP;

  const buildWhatsAppMessage = () => {
    const itemLines = items.map((item, i) =>
      `${i + 1}. ${item.name} (${item.category})\n   Qty: ${item.qty} × ₹${item.price} = ₹${item.price * item.qty}`
    ).join('\n');

    const customerName = user?.displayName || 'Guest';

    const message = `🛍️ *New Order — DNC Creates*\n\n${itemLines}\n\n━━━━━━━━━━━━━━━━\n👤 *Customer:* ${customerName}\n🧾 *Total Items:* ${totalItems}\n💰 *Grand Total:* ₹${grandTotal}${shipping > 0 ? ` (incl. ₹${shipping} shipping)` : ' (Free Shipping)'}\n\nPlease confirm availability and share payment details. Thank you! 🌸`;

    return encodeURIComponent(message);
  };

  const handleWhatsApp = async () => {
    if (user) {
      setIsProcessing(true);
      try {
        const orderData = {
          userId: user.uid,
          customerName: user.displayName || user.email || 'Customer',
          items: items.map(item => ({
            id: item.id,
            name: item.name,
            price: item.price,
            qty: item.qty,
            imageUrl: item.imageUrls?.[0] || item.imageUrl || item.image || null
          })),
          totalItems,
          subtotal: totalPrice,
          shipping,
          grandTotal,
          status: 'Pending',
          createdAt: serverTimestamp()
        };
        await addDoc(collection(db, 'orders'), orderData);
        clearCart();
      } catch (error) {
        console.error("Error saving order:", error);
      } finally {
        setIsProcessing(false);
      }
    }

    const url = `https://wa.me/${whatsappNumber}?text=${buildWhatsAppMessage()}`;
    window.open(url, '_blank');
  };

  if (items.length === 0) {
    return (
      <div className="min-h-[70vh] flex flex-col items-center justify-center py-24 px-4">
        <ShoppingBag size={80} strokeWidth={0.8} className="text-rose-gold opacity-20 mb-6" />
        <h2 className="font-display text-4xl text-deep-brown mb-3">Your cart is empty</h2>
        <p className="font-body text-deep-brown/60 mb-8 text-center max-w-sm">
          Discover our handcrafted jewellery and fill your cart with something beautiful.
        </p>
        <Link to="/shop" className="btn-primary">Browse Collection</Link>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto px-6 lg:px-8 py-12">
      <h1 className="font-display text-4xl text-deep-brown mb-2">Shopping Cart</h1>
      <div className="ornament mb-8"></div>

      {/* Guest Banner */}
      {!user && (
        <div className="mb-8 bg-champagne/60 border border-rose-gold/20 p-4 flex items-center justify-between rounded-sm">
          <p className="font-body text-deep-brown text-sm">
            <span className="font-medium">Login to save your cart across devices</span>
          </p>
          <Link to="/login" state={{ from: '/cart' }} className="btn-primary text-xs py-2 px-4">
            Login
          </Link>
        </div>
      )}

      <div className="flex flex-col lg:flex-row gap-10">
        {/* Left: Items */}
        <div className="flex-1">
          <div className="divide-y divide-rose-gold/10">
            {items.map(item => (
              <div key={item.id} className="flex gap-5 py-6 group">
                {/* Image */}
                <div className="w-24 bg-champagne rounded-sm overflow-hidden flex-shrink-0 aspect-square">
                  {(item.imageUrl || item.image || (item.imageUrls && item.imageUrls[0])) && (
                    <img src={item.imageUrl || item.image || (item.imageUrls && item.imageUrls[0])} alt={item.name} className="w-full h-full object-cover" />
                  )}
                </div>

                {/* Details */}
                <div className="flex-1 min-w-0">
                  <div className="flex justify-between items-start mb-1">
                    <div className="flex items-center gap-2">
                      <Link to={`/shop/${item.id}`} className="font-display text-lg text-deep-brown hover:text-rose-gold transition-colors line-clamp-1">
                        {item.name}
                      </Link>
                      {item.inStock === false && (
                        <span className="bg-red-100 text-red-600 text-[10px] uppercase font-bold px-2 py-0.5 rounded-sm whitespace-nowrap">
                          Out of Stock
                        </span>
                      )}
                    </div>
                    <button
                      onClick={() => removeItem(item.id)}
                      className="text-gray-300 hover:text-red-400 transition-colors ml-3 flex-shrink-0 opacity-0 group-hover:opacity-100"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                  <p className="font-body text-xs text-deep-brown/50 uppercase tracking-widest mb-3">{item.category}</p>

                  <div className="flex items-center justify-between">
                    {/* Qty Controls */}
                    <div className="flex items-center border border-rose-gold/20">
                      <button
                        onClick={() => updateQty(item.id, item.qty - 1)}
                        className="w-8 h-8 flex items-center justify-center text-deep-brown hover:text-rose-gold hover:bg-rose-gold/5 transition-colors"
                      >
                        <Minus size={14} />
                      </button>
                      <span className="w-8 text-center font-body text-sm text-deep-brown">{item.qty}</span>
                      <button
                        onClick={() => updateQty(item.id, item.qty + 1)}
                        className="w-8 h-8 flex items-center justify-center text-deep-brown hover:text-rose-gold hover:bg-rose-gold/5 transition-colors"
                      >
                        <Plus size={14} />
                      </button>
                    </div>

                    {/* Price */}
                    <div className="text-right">
                      <p className="font-body text-deep-brown font-medium">₹{(item.price * item.qty).toLocaleString()}</p>
                      {item.qty > 1 && (
                        <p className="text-xs text-deep-brown/40">₹{item.price} each</p>
                      )}
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>

          {/* Clear Cart */}
          <div className="mt-4 pt-4 border-t border-rose-gold/10">
            <button
              onClick={clearCart}
              className="font-body text-xs uppercase tracking-widest text-deep-brown/40 hover:text-red-500 transition-colors"
            >
              Clear Cart
            </button>
          </div>
        </div>

        {/* Right: Summary */}
        <div className="lg:w-80">
          <div className="bg-soft-white border border-rose-gold/20 p-6 rounded-sm sticky top-28">
            <h3 className="font-display text-2xl text-deep-brown mb-5">Order Summary</h3>

            <div className="space-y-3 font-body text-sm mb-5">
              <div className="flex justify-between text-deep-brown/70">
                <span>Subtotal ({totalItems} item{totalItems > 1 ? 's' : ''})</span>
                <span>₹{totalPrice.toLocaleString()}</span>
              </div>
              <div className="flex justify-between text-deep-brown/70">
                <span>Shipping</span>
                <span className={shipping === 0 ? 'text-green-600 font-medium' : ''}>
                  {shipping === 0 ? 'Free' : `₹${shipping}`}
                </span>
              </div>
              <div className="border-t border-rose-gold/20 pt-3 flex justify-between items-center">
                <span className="font-medium text-deep-brown">Grand Total</span>
                <span className="text-2xl text-rose-gold font-medium">₹{grandTotal.toLocaleString()}</span>
              </div>
            </div>

            {shipping > 0 && (
              <p className="text-xs font-body text-deep-brown/50 bg-champagne/50 rounded-sm p-2 text-center mb-5">
                🎁 Free shipping on orders above ₹999
              </p>
            )}

            {hasOutOfStock && (
              <div className="mb-5 bg-red-50 text-red-600 border border-red-100 p-3 rounded-sm text-xs font-body text-center leading-relaxed">
                One or more items in your cart are out of stock. Please remove them to proceed with your order.
              </div>
            )}

            <button
              onClick={handleWhatsApp}
              disabled={hasOutOfStock || items.length === 0 || isProcessing}
              className={`w-full flex items-center justify-center gap-2 py-4 font-body uppercase tracking-widest text-sm transition-colors ${
                hasOutOfStock || items.length === 0 || isProcessing
                  ? 'bg-gray-300 text-gray-400 cursor-not-allowed'
                  : 'bg-green-500 hover:bg-green-600 text-white'
              }`}
            >
              {isProcessing ? <Loader2 size={18} className="animate-spin" /> : <MessageCircle size={18} />}
              {isProcessing ? 'Processing...' : 'Order via WhatsApp'}
            </button>

            <Link to="/shop" className="block text-center mt-4 font-body text-xs text-deep-brown/50 hover:text-rose-gold transition-colors uppercase tracking-widest">
              Continue Shopping
            </Link>
          </div>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useLocation } from 'react-router-dom';
import { Mail, Phone, MapPin, CheckCircle, Clock } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { collection, addDoc, serverTimestamp } from 'firebase/firestore';
import { db } from '../../firebase';

export default function Contact() {
  const location = useLocation();
  const queryParams = new URLSearchParams(location.search);
  const subjectQuery = queryParams.get('subject') || '';

  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    type: subjectQuery ? 'Custom Order' : 'General Enquiry',
    message: subjectQuery ? `I am interested in a custom order related to: ${subjectQuery.replace('Custom Order Enquiry: ', '')}` : ''
  });

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);

  useEffect(() => {
    window.scrollTo(0, 0);
  }, []);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);

    try {
      await addDoc(collection(db, 'messages'), {
        ...formData,
        createdAt: serverTimestamp(),
        status: 'Unread'
      });

      setIsSuccess(true);

      // Fallback native email trigger (optional, user requested "sends email to owner")
      const adminEmail = import.meta.env.VITE_ADMIN_EMAIL || 'paulanik055@gmail.com';
      const mailtoLink = `mailto:${adminEmail}?subject=${encodeURIComponent(formData.type)}&body=${encodeURIComponent(`Name: ${formData.name}\nEmail: ${formData.email}\nPhone: ${formData.phone}\n\nMessage:\n${formData.message}`)}`;
      window.location.href = mailtoLink;

      setFormData({
        name: '',
        email: '',
        phone: '',
        type: 'General Enquiry',
        message: ''
      });

      setTimeout(() => setIsSuccess(false), 5000);
    } catch (error) {
      console.error("Error sending message:", error);
      alert("There was an error sending your message. Please try again.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="w-full">
      {/* Page Header */}
      <header className="bg-champagne py-16 text-center border-b border-rose-gold/20">
        <h1 className="text-5xl text-deep-brown mb-4">Get in Touch</h1>
        <div className="ornament"></div>
        <p className="font-body tracking-widest uppercase text-sm text-deep-brown/70 mt-4">
          We'd love to hear from you
        </p>
      </header>

      <section className="max-w-7xl mx-auto px-6 lg:px-8 py-24">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-16">

          {/* Contact Information */}
          <div className="lg:col-span-4 flex flex-col space-y-12">
            <div>
              <h2 className="font-display text-3xl text-deep-brown mb-6">Contact Information</h2>
              <p className="font-body text-deep-brown/70 leading-relaxed mb-8">
                Whether you have a question about our pieces, need help with an order, or want to discuss a custom design, our team is here to assist you.
              </p>

              <div className="space-y-6">
                <div className="flex items-start space-x-4">
                  <div className="w-10 h-10 rounded-full bg-champagne flex items-center justify-center shrink-0">
                    <Mail size={18} className="text-rose-gold" />
                  </div>
                  <div>
                    <h4 className="font-body uppercase tracking-wider text-xs font-medium text-deep-brown/60 mb-1">Email</h4>
                    <a href="mailto:hello@dnccreates.com" className="font-body text-deep-brown hover:text-rose-gold transition-colors">hello@dnccreates.com</a>
                  </div>
                </div>

                <div className="flex items-start space-x-4">
                  <div className="w-10 h-10 rounded-full bg-champagne flex items-center justify-center shrink-0">
                    <Phone size={18} className="text-rose-gold" />
                  </div>
                  <div>
                    <h4 className="font-body uppercase tracking-wider text-xs font-medium text-deep-brown/60 mb-1">Phone / WhatsApp</h4>
                    <a href="tel:+919876543210" className="font-body text-deep-brown hover:text-rose-gold transition-colors">+91 98765 43210</a>
                  </div>
                </div>

                <div className="flex items-start space-x-4">
                  <div className="w-10 h-10 rounded-full bg-champagne flex items-center justify-center shrink-0">
                    <Clock size={18} className="text-rose-gold" />
                  </div>
                  <div>
                    <h4 className="font-body uppercase tracking-wider text-xs font-medium text-deep-brown/60 mb-1">Working Hours</h4>
                    <p className="font-body text-deep-brown">Mon - Sat: 10AM - 6PM IST</p>
                  </div>
                </div>

                <div className="flex items-start space-x-4">
                  <div className="w-10 h-10 rounded-full bg-champagne flex items-center justify-center shrink-0">
                    <MapPin size={18} className="text-rose-gold" />
                  </div>
                  <div>
                    <h4 className="font-body uppercase tracking-wider text-xs font-medium text-deep-brown/60 mb-1">Studio Location</h4>
                    <p className="font-body text-deep-brown">Mumbai, India<br/>(Studio visits by appointment only)</p>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* Contact Form */}
          <div className="lg:col-span-8">
            <div className="bg-white p-8 md:p-12 border border-rose-gold/20 shadow-sm relative overflow-hidden">

              <AnimatePresence>
                {isSuccess && (
                  <motion.div 
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, scale: 0.95 }}
                    className="absolute inset-0 z-20 bg-white flex flex-col items-center justify-center text-center p-8"
                  >
                    <motion.div
                      initial={{ scale: 0 }}
                      animate={{ scale: 1 }}
                      transition={{ type: "spring", stiffness: 200, damping: 20 }}
                    >
                      <CheckCircle size={64} className="text-green-500 mb-6" strokeWidth={1.5} />
                    </motion.div>
                    <h3 className="font-display text-3xl text-deep-brown mb-2">Message Sent!</h3>
                    <p className="font-body text-deep-brown/70 max-w-sm">
                      Thank you for reaching out. We will get back to you within 24-48 business hours.
                    </p>
                  </motion.div>
                )}
              </AnimatePresence>

              <h2 className="font-display text-3xl text-deep-brown mb-8">Send us a Message</h2>

              <form onSubmit={handleSubmit} className="space-y-6">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div>
                    <label htmlFor="name" className="block font-body text-xs uppercase tracking-wider text-deep-brown/70 mb-2">Full Name *</label>
                    <input 
                      type="text" 
                      id="name"
                      name="name"
                      required
                      value={formData.name}
                      onChange={handleChange}
                      className="w-full bg-soft-white border border-rose-gold/30 px-4 py-3 font-body text-deep-brown focus:outline-none focus:border-rose-gold transition-colors"
                    />
                  </div>
                  <div>
                    <label htmlFor="email" className="block font-body text-xs uppercase tracking-wider text-deep-brown/70 mb-2">Email Address *</label>
                    <input 
                      type="email" 
                      id="email"
                      name="email"
                      required
                      value={formData.email}
                      onChange={handleChange}
                      className="w-full bg-soft-white border border-rose-gold/30 px-4 py-3 font-body text-deep-brown focus:outline-none focus:border-rose-gold transition-colors"
                    />
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div>
                    <label htmlFor="phone" className="block font-body text-xs uppercase tracking-wider text-deep-brown/70 mb-2">Phone Number</label>
                    <input 
                      type="tel" 
                      id="phone"
                      name="phone"
                      value={formData.phone}
                      onChange={handleChange}
                      className="w-full bg-soft-white border border-rose-gold/30 px-4 py-3 font-body text-deep-brown focus:outline-none focus:border-rose-gold transition-colors"
                    />
                  </div>
                  <div>
                    <label htmlFor="type" className="block font-body text-xs uppercase tracking-wider text-deep-brown/70 mb-2">Enquiry Type *</label>
                    <select 
                      id="type"
                      name="type"
                      required
                      value={formData.type}
                      onChange={handleChange}
                      className="w-full bg-soft-white border border-rose-gold/30 px-4 py-3 font-body text-deep-brown focus:outline-none focus:border-rose-gold transition-colors appearance-none"
                    >
                      <option>General Enquiry</option>
                      <option>Custom Order</option>
                      <option>Order Status</option>
                      <option>Return/Exchange</option>
                      <option>Other</option>
                    </select>
                  </div>
                </div>

                <div>
                  <label htmlFor="message" className="block font-body text-xs uppercase tracking-wider text-deep-brown/70 mb-2">Your Message *</label>
                  <textarea 
                    id="message"
                    name="message"
                    rows="5"
                    required
                    value={formData.message}
                    onChange={handleChange}
                    className="w-full bg-soft-white border border-rose-gold/30 px-4 py-3 font-body text-deep-brown focus:outline-none focus:border-rose-gold transition-colors resize-y"
                  ></textarea>
                </div>

                <div className="pt-2">
                  <button 
                    type="submit" 
                    disabled={isSubmitting}
                    className={`btn-primary w-full md:w-auto ${isSubmitting ? 'opacity-70 cursor-not-allowed' : ''}`}
                  >
                    {isSubmitting ? 'Sending...' : 'Send Message'}
                  </button>
                </div>
              </form>

            </div>
          </div>

        </div>
      </section>
    </div>
  );
}
